public class ExpressionTree {

    static class Node {
        String val;
        Node left, right;
        Node(String v) { val = v; }
        Node(String v, Node l, Node r) { val=v; left=l; right=r; }
    }

    public int evaluate(Node root) {
        if (root == null) return 0;
        if (root.left == null && root.right == null) {
            return Integer.parseInt(root.val); // leaf = number
        }
        int left = evaluate(root.left);
        int right = evaluate(root.right);
        // TODO: apply operator in root.val to left and right
        return 0;
    }

    public String infix(Node root) {
        if (root == null) return "";
        if (root.left == null && root.right == null) return root.val;
        // TODO: return "(" + infix(left) + root.val + infix(right) + ")"
        return "";
    }

    public static void main(String[] args) {
        ExpressionTree et = new ExpressionTree();
        // Build: (3 + (4 * 5))
        Node tree1 = new Node("+",
            new Node("3"),
            new Node("*", new Node("4"), new Node("5"))
        );
        System.out.println("Expression: " + et.infix(tree1));
        System.out.println("Result: " + et.evaluate(tree1));
        // Build: ((2 + 3) * (8 - 4))
        Node tree2 = new Node("*",
            new Node("+", new Node("2"), new Node("3")),
            new Node("-", new Node("8"), new Node("4"))
        );
        System.out.println("Expression: " + et.infix(tree2));
        System.out.println("Result: " + et.evaluate(tree2));
    }
}

import java.util.*;

public class FileSystemTree {

    static class FsNode {
        String name;
        boolean isDir;
        int size; // 0 for directories, actual for files
        List<FsNode> children = new ArrayList<>();
        FsNode(String name, boolean isDir, int size) {
            this.name = name; this.isDir = isDir; this.size = size;
        }
    }

    public void addChild(FsNode parent, FsNode child) {
        if (parent.isDir) parent.children.add(child);
        // Silently ignore if parent is a file
    }

    public int totalSize(FsNode node) {
        // TODO: if file return node.size; else sum totalSize of all children
        return 0;
    }

    public void printTree(FsNode node, int depth) {
        String indent = "  ".repeat(depth);
        String type = node.isDir ? "[DIR]" : "[FILE " + node.size + "B]";
        System.out.println(indent + node.name + " " + type);
        for (FsNode child : node.children) printTree(child, depth + 1);
    }

    public static void main(String[] args) {
        FileSystemTree fs = new FileSystemTree();
        FsNode root = new FsNode("root", true, 0);
        FsNode src = new FsNode("src", true, 0);
        FsNode main = new FsNode("Main.java", false, 1024);
        FsNode util = new FsNode("Utils.java", false, 512);
        FsNode readme = new FsNode("README.md", false, 256);
        fs.addChild(root, src); fs.addChild(root, readme);
        fs.addChild(src, main); fs.addChild(src, util);
        fs.printTree(root, 0);
        System.out.println("Total size: " + fs.totalSize(root) + " bytes");
    }
}

